mapper.select:
/* 사용자 위젯 목록 dataDashboard.selectDashboardWidgetList */ SELECT W.WIDGET_ID , W.LOG_ID , W.TITLE , W.VIZ_TYPE , W.VIZ_CONFIG , W.SORT_ORD , W.LAST_SQL_PARAMS AS LAST_TTSQ_PARAMS , DATE_FORMAT(W.LAST_EXEC_DT, '%Y-%m-%d %H:%i:%s') AS LAST_EXEC_DT , A.Q_CONTENT AS SQL_TITLE , A.TTSQ AS SQL_CONTENT , A.TTSQ_PARAM , A.AGENT_ID , B.AGENT_NM , A.REF_ID AS DATAMART_ID , C.DM_NM AS DATAMART_NM FROM TB_USER_DASHBOARD_WIDGET W JOIN TB_CHAT_LOG A ON W.LOG_ID = A.LOG_ID LEFT JOIN TB_AGT B ON A.AGENT_ID = B.AGENT_ID LEFT JOIN TB_DM C ON A.REF_ID = C.DATAMART_ID WHERE W.USER_ID = #{userId}
AND W.WIDGET_ID = #{widgetId}
ORDER BY W.SORT_ORD, W.WIDGET_ID

mapper.insert:
/* 위젯 저장 dataDashboard.saveDashboardWidget */
INSERT INTO TB_USER_DASHBOARD_WIDGET (
      WIDGET_ID
    , USER_ID
    , LOG_ID
    , TITLE
    , VIZ_TYPE
    , VIZ_CONFIG
    , TTSQ_PARAM
    , SORT_ORD
    , CREATE_DT
) VALUES (
      #{widgetId}
    , #{userId}
    , #{logId}
    , #{title}
    , #{vizType}
    , #{vizConfig}
    , #{ttsqParam}
    , #{sortOrd, jdbcType=INTEGER}
    , NOW()
)
ON DUPLICATE KEY UPDATE
      TITLE      = #{title}
    , VIZ_TYPE   = #{vizType}
    , VIZ_CONFIG = #{vizConfig}
    , SORT_ORD   = #{sortOrd, jdbcType=INTEGER}
    , MODIFY_DT  = NOW()

mapper.delete:
/* 위젯 삭제 dataDashboard.deleteDashboardWidget */
DELETE FROM TB_USER_DASHBOARD_WIDGET
WHERE WIDGET_ID = #{widgetId}
  AND USER_ID   = #{userId}

mapper.update:
/* 위젯 마지막 SQL 파라미터 저장 dataDashboard.updateWidgetLastParams */
UPDATE TB_USER_DASHBOARD_WIDGET
SET LAST_SQL_PARAMS = #{lastTtsqParams}
  , LAST_EXEC_DT    = NOW()
  , MODIFY_DT       = NOW()
WHERE WIDGET_ID = #{widgetId}
  AND USER_ID   = #{userId}

mapper.select:
/* 위젯 마지막 SQL 실행 일시 조회 dataDashboard.selectWidgetLastExecDt */
SELECT DATE_FORMAT(LAST_EXEC_DT, '%Y-%m-%d %H:%i:%s')
FROM TB_USER_DASHBOARD_WIDGET
WHERE WIDGET_ID = #{widgetId}
  AND USER_ID   = #{userId}
LIMIT 1

mapper.insert:
/* 레이아웃 저장 dataDashboard.saveDashboardLayout */
INSERT INTO TB_USER_DASHBOARD_LAYOUT (
      LAYOUT_ID
    , USER_ID
    , WIDGET_ID
    , SORT_ORD
    , X
    , Y
    , W
    , H
    , MIN_W
    , MAX_W
    , MIN_H
    , MAX_H
    , IS_VISIBLE
    , CREATE_DT
) VALUES (
      #{layoutId}
    , #{userId}
    , #{widgetId}
    , #{sortOrd,   jdbcType=INTEGER}
    , #{x,         jdbcType=INTEGER}
    , #{y,         jdbcType=INTEGER}
    , #{w,         jdbcType=INTEGER}
    , #{h,         jdbcType=INTEGER}
    , #{minW,      jdbcType=INTEGER}
    , #{maxW,      jdbcType=INTEGER}
    , #{minH,      jdbcType=INTEGER}
    , #{maxH,      jdbcType=INTEGER}
    , #{isVisible, jdbcType=TINYINT}
    , NOW()
)
ON DUPLICATE KEY UPDATE
      SORT_ORD   = COALESCE(#{sortOrd,   jdbcType=INTEGER}, SORT_ORD)
    , X          = COALESCE(#{x,         jdbcType=INTEGER}, X)
    , Y          = COALESCE(#{y,         jdbcType=INTEGER}, Y)
    , W          = COALESCE(#{w,         jdbcType=INTEGER}, W)
    , H          = COALESCE(#{h,         jdbcType=INTEGER}, H)
    , MIN_W      = COALESCE(#{minW,      jdbcType=INTEGER}, MIN_W)
    , MAX_W      = COALESCE(#{maxW,      jdbcType=INTEGER}, MAX_W)
    , MIN_H      = COALESCE(#{minH,      jdbcType=INTEGER}, MIN_H)
    , MAX_H      = COALESCE(#{maxH,      jdbcType=INTEGER}, MAX_H)
    , IS_VISIBLE = COALESCE(#{isVisible, jdbcType=TINYINT}, IS_VISIBLE)
    , MODIFY_DT  = NOW()

/* 레이아웃 일괄 저장 dataDashboard.saveLayoutBatch */
INSERT INTO TB_USER_DASHBOARD_LAYOUT
    (LAYOUT_ID, USER_ID, WIDGET_ID, SORT_ORD, X, Y, W, H, MIN_W, MAX_W, MIN_H, MAX_H, IS_VISIBLE, CREATE_DT)
VALUES

    (
      #{item.layoutId}
    , #{userId}
    , #{item.widgetId}
    , #{item.sortOrd,   jdbcType=INTEGER}
    , #{item.x,         jdbcType=INTEGER}
    , #{item.y,         jdbcType=INTEGER}
    , #{item.w,         jdbcType=INTEGER}
    , #{item.h,         jdbcType=INTEGER}
    , #{item.minW,      jdbcType=INTEGER}
    , #{item.maxW,      jdbcType=INTEGER}
    , #{item.minH,      jdbcType=INTEGER}
    , #{item.maxH,      jdbcType=INTEGER}
    , #{item.isVisible, jdbcType=TINYINT}
    , NOW()
    )

ON DUPLICATE KEY UPDATE
      SORT_ORD   = VALUES(SORT_ORD)
    , X          = VALUES(X)
    , Y          = VALUES(Y)
    , W          = VALUES(W)
    , H          = VALUES(H)
    , MIN_W      = VALUES(MIN_W)
    , MAX_W      = VALUES(MAX_W)
    , MIN_H      = VALUES(MIN_H)
    , MAX_H      = VALUES(MAX_H)
    , IS_VISIBLE = VALUES(IS_VISIBLE)
    , MODIFY_DT  = NOW()

mapper.delete:
/* 전체 레이아웃 초기화 dataDashboard.deleteAllLayouts */
DELETE FROM TB_USER_DASHBOARD_LAYOUT
WHERE USER_ID = #{userId}

/* 레이아웃 삭제 dataDashboard.deleteDashboardLayout */
DELETE FROM TB_USER_DASHBOARD_LAYOUT
WHERE WIDGET_ID = #{widgetId}
  AND USER_ID   = #{userId}
